const now = Date.now();
const checks = [];
const alerts = [];
const failoverCandidates = [];

const paperclipResult = $('Check Paperclip').first().json;
const paperclipBody = paperclipResult.body || paperclipResult;
const paperclipOk = paperclipResult.statusCode === 200 || paperclipBody.status === 'ok';
checks.push({
  name: 'paperclip_api',
  status: paperclipOk ? 'healthy' : 'unhealthy',
  latencyMs: paperclipResult.responseTime || null,
  detail: paperclipOk ? 'API responding' : 'API not responding or returned error'
});
if (!paperclipOk) {
  alerts.push({ severity: 'critical', source: 'paperclip_api', message: 'Paperclip API is not responding' });
}

const agentData = $('Check Agent Heartbeats').first().json;
const agents = Array.isArray(agentData) ? agentData : (agentData.data || []);
const heartbeatEnabledAgents = agents.filter(agent => agent.runtimeConfig?.heartbeat?.enabled);
const staleAgents = [];
let healthyAgents = 0;
const scoutAgent = agents.find(agent => agent.name === 'scout') || null;
const scoutAgentId = scoutAgent?.id || null;

for (const agent of heartbeatEnabledAgents) {
  const intervalSec = agent.runtimeConfig?.heartbeat?.intervalSec || 0;
  if (!intervalSec) continue;

  const lastRaw = agent.lastHeartbeatAt || agent.lastHeartbeat || null;
  const lastBeat = lastRaw ? new Date(lastRaw).getTime() : 0;
  const staleSec = lastBeat ? (now - lastBeat) / 1000 : Number.POSITIVE_INFINITY;
  const maxAllowed = intervalSec * 2;

  if (staleSec > maxAllowed) {
    staleAgents.push({
      agent: agent.name,
      lastHeartbeatAt: lastRaw || 'never',
      staleSec: Math.round(staleSec),
      expectedIntervalSec: intervalSec
    });
  } else {
    healthyAgents++;
  }
}

checks.push({
  name: 'agent_heartbeats',
  status: staleAgents.length === 0 ? 'healthy' : 'degraded',
  detail: `${healthyAgents} healthy, ${staleAgents.length} stale`,
  staleAgents
});

if (staleAgents.length > 0) {
  const criticalAgents = staleAgents.filter(agent => ['atlas', 'sentinel', 'argus', 'scout'].includes(agent.agent));
  alerts.push({
    severity: criticalAgents.length > 0 ? 'critical' : 'warning',
    source: 'agent_heartbeats',
    message: `${staleAgents.length} agent(s) missed heartbeat: ${staleAgents.map(agent => agent.agent).join(', ')}`
  });
}

const stuckData = $('Check Stuck Tickets').first().json;
const stuckTickets = Array.isArray(stuckData) ? stuckData : (stuckData.data || []);
checks.push({
  name: 'stuck_tickets',
  status: stuckTickets.length === 0 ? 'healthy' : 'degraded',
  detail: `${stuckTickets.length} ticket(s) in_progress > 1 hour`,
  tickets: stuckTickets.map(ticket => ({
    id: ticket.id,
    title: ticket.title,
    assigneeAgentId: ticket.assigneeAgentId || null,
    executionAgentNameKey: ticket.executionAgentNameKey || null,
    updatedAt: ticket.updatedAt || null
  }))
});
if (stuckTickets.length >= 3) {
  alerts.push({
    severity: 'warning',
    source: 'stuck_tickets',
    message: `${stuckTickets.length} tickets stuck in_progress for more than one hour`
  });
}

const staleTodoData = $('Check Failed Tickets').first().json;
const staleTodoTickets = Array.isArray(staleTodoData) ? staleTodoData : (staleTodoData.data || []);
for (const ticket of staleTodoTickets) {
  const isScout = ticket.executionAgentNameKey === 'scout' || ticket.assignee === 'scout' || (scoutAgentId && ticket.assigneeAgentId === scoutAgentId);
  const hasExecutionLock = !!ticket.executionRunId || !!ticket.executionLockedAt;
  const alreadyFailoverTagged = !!(ticket.metadata && ticket.metadata.failoverFrom);

  if (isScout && hasExecutionLock && !alreadyFailoverTagged) {
    failoverCandidates.push({
      ticketId: ticket.id,
      agentName: 'scout',
      adapterType: scoutAgent?.adapterType || 'cursor',
      requestedModel: scoutAgent?.adapterConfig?.model || 'auto',
      failureReason: 'stalled scout execution detected by health monitor',
      errorOutput: `stalled_execution_run=${ticket.executionRunId || 'unknown'}`
    });
  }
}

checks.push({
  name: 'stalled_scout_executions',
  status: failoverCandidates.length === 0 ? 'healthy' : 'degraded',
  detail: `${failoverCandidates.length} stalled scout ticket(s) detected`,
  failoverCandidates
});
if (failoverCandidates.length > 0) {
  alerts.push({
    severity: 'warning',
    source: 'scout_capacity_recovery',
    message: `${failoverCandidates.length} stalled scout ticket(s) normalized into rate-limit-failover`
  });
}

const overallHealthy = checks.every(check => check.status === 'healthy');
return [{
  json: {
    healthy: overallHealthy,
    timestamp: new Date().toISOString(),
    checks,
    alerts,
    hasAlerts: alerts.length > 0,
    failoverCandidates
  }
}];

const candidates = $('Evaluate Health').first().json.failoverCandidates || [];
const results = [];
const webhookBase = $env.N8N_WEBHOOK_BASE_URL || 'http://127.0.0.1:5678';

for (const candidate of candidates) {
  try {
    const resp = await this.helpers.httpRequest({
      method: 'POST',
      url: webhookBase + '/webhook/rate-limit-failover',
      body: candidate,
      headers: { 'Content-Type': 'application/json' },
      timeout: 15000,
    });
    results.push({ ticketId: candidate.ticketId, agent: candidate.agentName, status: 'triggered', response: resp });
  } catch (err) {
    results.push({ ticketId: candidate.ticketId, agent: candidate.agentName, status: 'failed', error: err.message });
  }
}

return [{ json: { failoverResults: results, triggered: results.length } }];

const now = new Date().toISOString();
const webhookBody = $('Webhook Trigger').first().json;
const receivedAt = webhookBody.headers && webhookBody.headers['x-request-start']
  ? webhookBody.headers['x-request-start']
  : now;

let healthy = null;
let checks = [];
let alerts = [];
try {
  const eh = $('Evaluate Health').first().json;
  healthy = eh.healthy;
  checks = (eh.checks || []).map(c => ({ name: c.name, status: c.status }));
  alerts = eh.alerts || [];
} catch (e) {
  // Evaluate Health not in execution path — fall through with defaults
}

return [{
  json: {
    workflow: 'hive-health-check',
    endpoint: 'health-check',
    kind: 'deterministic',
    status: 'completed',
    receivedAt,
    completedAt: now,
    timeoutMs: 10000,
    success: true,
    result: JSON.stringify({ healthy, checks, alerts })
  }
}];
